from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import os
import re

app = Flask(__name__)

w3 = Web3()

NONCE_STORE = {}
SIGNED_MESSAGE_PREFIX = "Login to Web3 Authentication"
ADDRESS_RE = re.compile(r"^0x[a-fA-F0-9]{40}$")

def normalize_address(address):
    if not isinstance(address, str) or not ADDRESS_RE.match(address):
        return None
    return Web3.to_checksum_address(address)

def build_message(message, nonce):
    return f"{SIGNED_MESSAGE_PREFIX}\n\nMessage: {message}\nNonce: {nonce}"

def verify_signature(address, message, signature):
    try:
        if not all(isinstance(x, str) for x in [address, message, signature]):
            return False, None

        checksum_address = normalize_address(address)
        if not checksum_address:
            return False, None

        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(encoded_message, signature=signature)

        if Web3.to_checksum_address(recovered_address) != checksum_address:
            return False, recovered_address

        return True, recovered_address
    except Exception:
        return False, None

@app.route("/nonce", methods=["POST"])
def nonce():
    data = request.get_json(silent=True) or {}
    address = data.get("address")

    checksum_address = normalize_address(address)
    if not checksum_address:
        return jsonify({"error": "Invalid address"}), 400

    nonce = Web3.keccak(text=f"{checksum_address}:{os.urandom(16).hex()}").hex()
    NONCE_STORE[checksum_address] = nonce

    message = build_message("Please sign this message to authenticate.", nonce)
    return jsonify({
        "address": checksum_address,
        "nonce": nonce,
        "message": message
    }), 200

@app.route("/authenticate", methods=["POST"])
def authenticate():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    message = data.get("message")
    signature = data.get("signature")

    checksum_address = normalize_address(address)
    if not checksum_address:
        return jsonify({"authenticated": False, "error": "Invalid address"}), 400

    if not message or not signature:
        return jsonify({"authenticated": False, "error": "Missing message or signature"}), 400

    expected_nonce = NONCE_STORE.get(checksum_address)
    if not expected_nonce:
        return jsonify({"authenticated": False, "error": "Nonce not found"}), 400

    if expected_nonce not in message:
        return jsonify({"authenticated": False, "error": "Invalid or expired nonce"}), 401

    ok, recovered_address = verify_signature(checksum_address, message, signature)
    if not ok:
        return jsonify({
            "authenticated": False,
            "error": "Signature verification failed",
            "recovered_address": recovered_address
        }), 401

    NONCE_STORE.pop(checksum_address, None)

    return jsonify({
        "authenticated": True,
        "address": checksum_address,
        "recovered_address": Web3.to_checksum_address(recovered_address)
    }), 200

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200

